class TelemetryClient {
  constructor() {
    this.context = {
      keys: { cloudRole: 'cloudRole' },
      tags: {},
    };
    this.config = {};
  }
}

class SetupChain {
  constructor(client) {
    this.client = client;
  }

  setAutoCollectConsole() {
    return this;
  }

  setAutoCollectDependencies() {
    return this;
  }

  setAutoCollectExceptions() {
    return this;
  }

  setAutoCollectPerformance() {
    return this;
  }

  setAutoCollectRequests() {
    return this;
  }

  setUseDiskRetryCaching() {
    return this;
  }

  setSendLiveMetrics() {
    return this;
  }

  start() {
    return this.client;
  }
}

const defaultClient = new TelemetryClient();

function setup() {
  return new SetupChain(defaultClient);
}

const KnownSeverityLevel = {
  Verbose: 0,
  Information: 1,
  Warning: 2,
  Error: 3,
  Critical: 4,
};

module.exports = { setup, defaultClient, KnownSeverityLevel, TelemetryClient };
module.exports.default = module.exports;
